2619                                                     BinaryOperator *SRem,
2620                                                     const APInt &C) {
2621   // Match an 'is positive' or 'is negative' comparison of remainder by a
2622   // constant power-of-2 value:
2623   // (X % pow2C) sgt/slt 0
2624   const ICmpInst::Predicate Pred = Cmp.getPredicate();
2625   if (Pred != ICmpInst::ICMP_SGT && Pred != ICmpInst::ICMP_SLT &&
2626       Pred != ICmpInst::ICMP_EQ && Pred != ICmpInst::ICMP_NE)
2627     return nullptr;
2628 
2629   // TODO: The one-use check is standard because we do not typically want to
2630   //       create longer instruction sequences, but this might be a special-case
2631   //       because srem is not good for analysis or codegen.
2632   if (!SRem->hasOneUse())
2633     return nullptr;
2634 
