2639   // For cmp_sgt/cmp_slt only zero valued C is handled.
2640   // For cmp_eq/cmp_ne only positive valued C is handled.
2641   if (((Pred == ICmpInst::ICMP_SGT || Pred == ICmpInst::ICMP_SLT) &&
2642        !C.isZero()) ||
2643       ((Pred == ICmpInst::ICMP_EQ || Pred == ICmpInst::ICMP_NE) &&
2644        !C.isStrictlyPositive()))
